dashboard.definition:
{
  "visualizations": {
    "viz_chat_output": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_chat"
      },
      "options": {
        "columnFormat": {
          "gemini_analysis": {
            "width": 900
          }
        }
      }
    },
    "viz_bg_main": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#0F2027",
        "strokeColor": "#00B4D8",
        "strokeWidth": 2
      }
    },
    "viz_header_text": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## 🤖 Gemini SOC Chat Assistant (Studio Edition)\n\nPaste log mentah, pilih persona, dan ajukan instruksi analitik mendalam secara seketika. AI akan merespons langsung dalam tabel di bawah dengan rekomendasi teknis dan pemetaan **MITRE ATT&CK**.",
        "backgroundColor": "transparent"
      }
    },
    "viz_pills": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "<span style=\"background:rgba(255,255,255,0.12); color:#b0d4e8; padding:4px 12px; border-radius:20px; font-size:12px; margin-right:8px;\">✅ Anti-Echo V2.1</span> <span style=\"background:rgba(255,255,255,0.12); color:#b0d4e8; padding:4px 12px; border-radius:20px; font-size:12px; margin-right:8px;\">✅ 5 Persona AI</span> <span style=\"background:rgba(255,255,255,0.12); color:#b0d4e8; padding:4px 12px; border-radius:20px; font-size:12px;\">✅ Dashboard Studio Layout</span>",
        "backgroundColor": "transparent"
      }
    }
  },
  "dataSources": {
    "ds_chat": {
      "type": "ds.search",
      "options": {
        "query": "| makeresults | eval _raw=$raw_data|s$ | geminianalyze prompt=$prompt|s$ role=$role|s$ model=$model|s$ | table gemini_analysis",
        "queryParameters": {
          "earliest": "-1m",
          "latest": "now"
        }
      }
    }
  },
  "inputs": {
    "input_model": {
      "type": "input.dropdown",
      "options": {
        "items": [
          {"label": "Gemma 4 31B IT", "value": "gemma-4-31b-it"},
          {"label": "Gemini 3.1 Pro", "value": "gemini-3.1-pro"},
          {"label": "Gemini 3 Flash", "value": "gemini-3-flash"}
        ],
        "defaultValue": "gemma-4-31b-it",
        "token": "model"
      },
      "title": "🧠 Model AI"
    },
    "input_role": {
      "type": "input.dropdown",
      "options": {
        "items": [
          {"label": "SOC Analyst", "value": "soc_clean_report"},
          {"label": "Threat Hunter", "value": "threat_hunter"},
          {"label": "Malware Analyst", "value": "malware_analyst"},
          {"label": "Executive", "value": "executive_report"},
          {"label": "JSON Extractor", "value": "json_extractor"}
        ],
        "defaultValue": "soc_clean_report",
        "token": "role"
      },
      "title": "🎭 Persona AI"
    },
    "input_raw": {
      "type": "input.text",
      "options": {
        "defaultValue": "EventID=4625 User=Administrator",
        "token": "raw_data"
      },
      "title": "📋 Data Mentah / Log (Paste di sini)"
    },
    "input_prompt": {
      "type": "input.text",
      "options": {
        "defaultValue": "Tolong analisa log ini dan temukan potensial brute force.",
        "token": "prompt"
      },
      "title": "💬 Pertanyaan / Instruksi Analisis (Lalu tekan Enter)"
    }
  },
  "layout": {
    "type": "absolute",
    "options": {
      "display": "auto",
      "backgroundColor": "#070E14"
    },
    "structure": [
      {
        "item": "viz_bg_main",
        "type": "block",
        "position": {"x": 20, "y": 20, "w": 1160, "h": 150}
      },
      {
        "item": "viz_header_text",
        "type": "block",
        "position": {"x": 40, "y": 40, "w": 1120, "h": 80}
      },
      {
        "item": "viz_pills",
        "type": "block",
        "position": {"x": 40, "y": 120, "w": 1120, "h": 40}
      },
      {
        "item": "input_model",
        "type": "input",
        "position": {"x": 20, "y": 190, "w": 280, "h": 60}
      },
      {
        "item": "input_role",
        "type": "input",
        "position": {"x": 320, "y": 190, "w": 280, "h": 60}
      },
      {
        "item": "input_raw",
        "type": "input",
        "position": {"x": 20, "y": 270, "w": 1160, "h": 60}
      },
      {
        "item": "input_prompt",
        "type": "input",
        "position": {"x": 20, "y": 350, "w": 1160, "h": 60}
      },
      {
        "item": "viz_chat_output",
        "type": "block",
        "position": {"x": 20, "y": 430, "w": 1160, "h": 500}
      }
    ]
  }
}
